import '../lib/package_release.dart';
import '../lib/release_selector.dart';
import '../lib/semantic_version.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

PackageRelease release(String version) {
  return PackageRelease.fromText('renderer', version);
}

void main() {
  check(
    SemanticVersion.parse(
          '1.4.0',
        ).compareTo(SemanticVersion.parse('1.4.0-rc.2')) >
        0,
    'a stable release outranks its prerelease',
  );
  check(
    SemanticVersion.parse(
          '1.4.0-rc.10',
        ).compareTo(SemanticVersion.parse('1.4.0-rc.2')) >
        0,
    'numeric prerelease identifiers use numeric precedence',
  );

  final selected = ReleaseSelector().bestCompatible(<PackageRelease>[
    release('1.3.9'),
    release('1.5.0'),
    release('2.1.0'),
  ], '>=1.4.0 <2.0.0');
  check(
    selected?.version.toString() == '1.5.0',
    'all clauses in one compatibility range must hold',
  );

  print('feedback tests passed');
}
